import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How are student loan payments calculated?", a: "Student loan payments are calculated from the balance, interest rate, repayment term, and when repayment begins after any grace period." },
  { q: "What is the difference between subsidized and unsubsidized loans?", a: "Subsidized federal loans may have interest paid by the government during certain periods. Unsubsidized loans usually accrue interest from disbursement." },
  { q: "What is income-based repayment?", a: "Income-based repayment estimates a payment from discretionary income instead of only the loan balance and term." },
  { q: "How do you qualify for student loan forgiveness?", a: "Eligibility depends on the program, loan type, employer, repayment plan, and payment history. Federal programs have specific rules." },
  { q: "Should you pay off student loans or invest?", a: "Compare your loan rate, employer matches, emergency savings, and risk tolerance. High-interest debt often deserves priority." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const payment = (amount: number, apr: number, years: number) => {
  const r = apr / 100 / 12;
  const n = years * 12;
  if (r === 0) return amount / n;
  return amount * r / (1 - Math.pow(1 + r, -n));
};

export default function StudentLoanCalculator() {
  useCurrencyVersion();
  const [amount, setAmount] = useState(30000);
  const [apr, setApr] = useState(5);
  const [years, setYears] = useState(10);
  const [grace, setGrace] = useState(6);
  const result = useMemo(() => {
    const accrued = amount * (apr / 100 / 12) * grace;
    const balance = amount + accrued;
    const monthly = payment(balance, apr, years);
    const totalPaid = monthly * years * 12;
    const incomeBased = Math.max(0, ((45000 - 22590) * 0.1) / 12);
    return { accrued, balance, monthly, totalInterest: totalPaid - amount, totalPaid, incomeBased };
  }, [amount, apr, years, grace]);
  const plans = [
    { name: "Standard 10yr", years: 10, monthly: payment(30000, 5, 10) },
    { name: "Graduated", years: 10, monthly: payment(30000, 5, 10) * 0.75 },
    { name: "Extended 25yr", years: 25, monthly: payment(30000, 5, 25) },
    { name: "Income-Based", years: 20, monthly: 187 },
  ].map((p) => ({ ...p, totalPaid: p.monthly * p.years * 12, interest: p.monthly * p.years * 12 - 30000 }));

  return (
    <>
      <SEOHead title="Free Student Loan Calculator Online - Calculate Student Loan Payments Instantly | CalcHive" description="Free online student loan calculator. Calculate monthly student loan payments, total interest and compare repayment plans for any loan amount and rate instantly. 100% free, no signup required." canonical="/student-loan-calculator" keywords="free student loan calculator, student loan payment calculator free online, calculate student loan interest free, student loan repayment calculator free, college loan calculator free" category="Financial Calculators" breadcrumbName="Free Student Loan Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Student Loan Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate student loan payments, total interest, grace period accrual, and income-based repayment.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Loan amount</label><input type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={apr} onChange={(e) => setApr(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Loan term (years)</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Grace period (months)</label><input type="number" value={grace} onChange={(e) => setGrace(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{money(result.totalInterest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total paid</p><p className="text-lg font-extrabold text-foreground">{money(result.totalPaid)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Income-based estimate</p><p className="text-lg font-extrabold text-foreground">{money(result.incomeBased)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Student Loan Payments for Free</h2><p className="text-muted-foreground leading-relaxed">This calculator adds estimated interest during the grace period, then amortizes the balance over your selected repayment term.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Compare Student Loan Repayment Plans</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Student Loan Repayment Plans Comparison - $30,000 at 5%</caption><thead className="bg-muted/60"><tr>{["Repayment Plan", "Monthly Payment", "Repayment Period", "Total Interest", "Total Paid"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{plans.map((row) => <tr key={row.name}><td className="py-2.5 px-3 font-semibold">{row.name}</td><td className="py-2.5 px-3">{money(row.monthly)}</td><td className="py-2.5 px-3">{row.years} years</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.totalPaid)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free College Loan Payment Calculator for Students</h2><p className="text-muted-foreground leading-relaxed">Use the result to compare standard repayment with income-based options and understand the cost of interest over time.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/student-loan-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


